import{_ as t,o as r,c as a,a5 as o}from"./chunks/framework.JW9VOlAI.js";const i="/pr-preview/pr-80/diagrams/pm-onion-lgt.svg",n="/pr-preview/pr-80/diagrams/pm-onion-drk.svg",s="/pr-preview/pr-80/diagrams/high-level-arch-lgt.svg",c="/pr-preview/pr-80/diagrams/high-level-arch-drk.svg",f=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{},"headers":[],"relativePath":"overview/architecture.md","filePath":"overview/architecture.md"}'),h={name:"overview/architecture.md"};function l(p,e,d,u,m,g){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>Platform Mesh is a composable platform built on the <a href="/pr-preview/pr-80/overview/principles.html">Kubernetes Resource Model (KRM)</a>. Rather than enforcing rigid IaaS/PaaS/SaaS layers, it provides a single mechanism for offering, discovering, and managing services of any kind. This page shows how the major components fit together.</p><h2 id="component-overview" tabindex="-1">Component Overview <a class="header-anchor" href="#component-overview" aria-label="Permalink to &quot;Component Overview&quot;">​</a></h2><p>The following onion diagram shows the concentric layers of the Platform Mesh stack, with kcp at the core and each outer ring adding capabilities -- control planes, identity and authorization, and finally portal, extensibility, and API composition.</p><div class="onion-light"><p><img src="'+i+'" alt="Platform Mesh onion architecture diagram"></p></div><div class="onion-dark"><p><img src="'+n+'" alt="Platform Mesh onion architecture diagram"></p></div><h2 id="component-descriptions" tabindex="-1">Component Descriptions <a class="header-anchor" href="#component-descriptions" aria-label="Permalink to &quot;Component Descriptions&quot;">​</a></h2><h3 id="ui-layer" tabindex="-1">UI Layer <a class="header-anchor" href="#ui-layer" aria-label="Permalink to &quot;UI Layer&quot;">​</a></h3><p><strong>Platform Mesh Portal</strong> is the reference implementation of a consumer-facing portal, built on <a href="https://openmfp.io" target="_blank" rel="noreferrer">OpenMFP</a> and the <a href="https://luigi-project.io" target="_blank" rel="noreferrer">Luigi</a> micro-frontend framework. It composes technology-agnostic frontend modules into a unified portal at runtime. Consumers can use the provided UI libraries to build a fully customized portal tailored to their needs. Platform Mesh also offers ways to declaratively configure UIs through Kubernetes-native ContentConfiguration CRDs, removing the need for UI development in many cases -- adding a new UI module requires no redeployment of the portal itself.</p><p><strong>Kubernetes GraphQL Gateway</strong> exposes kcp&#39;s KRM resources through a GraphQL interface. It supports single-cluster, kcp, and multi-cluster modes, giving the portal (and other clients) a typed, queryable API surface over the same resources accessible via <code>kubectl</code>.</p><h3 id="core-control-plane" tabindex="-1">Core Control Plane <a class="header-anchor" href="#core-control-plane" aria-label="Permalink to &quot;Core Control Plane&quot;">​</a></h3><p><strong>kcp</strong> is the heart of Platform Mesh. It extracts the Kubernetes declarative API server and strips away container orchestration, repurposing it for service management. kcp provides hierarchical <a href="/pr-preview/pr-80/concepts/control-planes.html">workspaces</a> (each behaving like an independent Kubernetes API endpoint), the <a href="/pr-preview/pr-80/concepts/api-export-binding.html">APIExport/APIBinding</a> mechanism for cross-workspace service sharing, and horizontal scaling through sharding. A key property is that kcp workspaces are cheap -- multiple logical clusters share a single process and etcd instance, isolated by storage prefix rather than separate infrastructure.</p><p><strong>Account Controller</strong> manages the <a href="/pr-preview/pr-80/concepts/account-model.html">Account Model</a>, which maps organizational structure (organizations, teams, environments) into kcp&#39;s workspace hierarchy. Each account node is an isolated control plane with its own API surface, identity realm, and authorization store. Policies flow downward through the hierarchy.</p><p><strong>Extension Controller</strong> processes ContentConfiguration CRDs that register micro-frontend extensions with the Platform Mesh Portal. It validates configurations asynchronously and stores the result so the portal can serve them at request time.</p><h3 id="identity-authorization" tabindex="-1">Identity &amp; Authorization <a class="header-anchor" href="#identity-authorization" aria-label="Permalink to &quot;Identity &amp; Authorization&quot;">​</a></h3><p><strong>Keycloak</strong> provides OpenID Connect (OIDC) authentication for the platform. Each organization gets its own Keycloak realm, supporting federation so organizations can bring their own identity provider.</p><p><strong>OpenFGA</strong> implements Relationship-Based Access Control (ReBAC), modeled after Google&#39;s Zanzibar system. Authorization state is expressed as relationship tuples (user, relation, object), and permissions propagate through a graph. Each organization gets an isolated OpenFGA store, and the authorization schema updates dynamically as new API bindings are activated. OpenFGA is connected to kcp natively via its authorizer chain, providing fine-grained authorization decisions alongside standard Kubernetes RBAC.</p><h3 id="infrastructure" tabindex="-1">Infrastructure <a class="header-anchor" href="#infrastructure" aria-label="Permalink to &quot;Infrastructure&quot;">​</a></h3><p>These components are internal to the Platform Mesh stack -- they are used by platform owners to deploy and manage the platform itself, not by consumers or providers directly.</p><p><strong>Flux</strong> provides GitOps-based continuous delivery, reconciling desired state from Git repositories to deploy and update Platform Mesh components.</p><p><strong>OCM (Open Component Model)</strong> handles component packaging and versioning, providing a supply chain for delivering platform components and extensions.</p><h3 id="connectivity" tabindex="-1">Connectivity <a class="header-anchor" href="#connectivity" aria-label="Permalink to &quot;Connectivity&quot;">​</a></h3><p>Three mechanisms bridge the gap between service provider clusters and the Platform Mesh control plane. Each serves a different use case:</p><p><strong><a href="/pr-preview/pr-80/overview/api-syncagent.html">api-syncagent</a></strong> is the primary integration path for standard CRD-based services. It runs on a service provider&#39;s Kubernetes cluster and publishes that cluster&#39;s CRDs as APIExports in kcp. Synchronization is bidirectional: spec flows from kcp to the service cluster, status flows back. Configuration is driven by PublishedResource CRDs. This is the recommended starting point for most providers.</p><p><strong><a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a></strong> is a Go library extending <code>controller-runtime</code> for building custom syncers. Use it when providers need full control over sync logic or work with non-CRD APIs (aggregated API servers, custom API servers). It requires more development effort but offers complete flexibility.</p><p><strong><a href="https://github.com/kube-bind/kube-bind" target="_blank" rel="noreferrer">kube-bind</a></strong> 🚧 <em>Work in progress</em> -- is an alternative to api-syncagent that also allows providers to publish their APIs into the mesh. In addition, kube-bind enables pushing those APIs down from Platform Mesh to consumer clusters running vanilla Kubernetes, making them available as if they were native resources on the consumer&#39;s own cluster.</p><h2 id="how-components-interact" tabindex="-1">How Components Interact <a class="header-anchor" href="#how-components-interact" aria-label="Permalink to &quot;How Components Interact&quot;">​</a></h2><div class="arch-light"><p><img src="'+s+'" alt="Platform Mesh high-level architecture"></p></div><div class="arch-dark"><p><img src="'+c+'" alt="Platform Mesh high-level architecture"></p></div><p>A typical request flows through the stack as follows. A developer opens the Platform Mesh Portal, which loads micro-frontend modules registered through ContentConfiguration CRDs. The portal calls the Kubernetes GraphQL Gateway, which translates the request into standard KRM operations against a kcp workspace. kcp authenticates the request via Keycloak (OIDC token validation) and authorizes it through its authorizer chain, which includes Kubernetes RBAC and OpenFGA for fine-grained relationship-based decisions.</p><p>When a consumer creates a resource in their workspace -- for example, a <code>DatabaseClaim</code> -- that resource exists in kcp&#39;s declarative API surface via an <a href="/pr-preview/pr-80/concepts/api-export-binding.html">APIBinding</a>. The corresponding service provider has published a matching APIExport, and one of the three connectivity mechanisms (typically api-syncagent) synchronizes the resource down to the provider&#39;s service cluster. The provider&#39;s operator reconciles the resource, provisions the actual database, and writes status back through the same sync path. The consumer sees the updated status in their workspace, whether they check via <code>kubectl</code>, the GraphQL gateway, or the portal UI.</p><p>This architecture means that providers and consumers never interact directly. The control plane mediates all communication, providing isolation, authorization, and a uniform declarative interface regardless of what the underlying service actually is.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/concepts/account-model.html">Account Model</a> -- how organizational hierarchy maps to workspaces</li><li><a href="/pr-preview/pr-80/concepts/control-planes.html">Control Planes</a> -- kcp workspaces and the control plane concept</li><li><a href="/pr-preview/pr-80/concepts/api-export-binding.html">APIExport and APIBinding</a> -- the service sharing mechanism</li><li><a href="/pr-preview/pr-80/overview/api-syncagent.html">api-syncagent</a> -- publishing CRDs into the mesh</li><li><a href="/pr-preview/pr-80/overview/multi-cluster-runtime.html">multi-cluster-runtime</a> -- building custom syncers</li><li><a href="/pr-preview/pr-80/overview/principles.html">Guiding Principles</a> -- the design philosophy behind Platform Mesh</li></ul>',34)])])}const w=t(h,[["render",l]]);export{f as __pageData,w as default};
